mapper.select:
SELECT FROM private_message pm LEFT JOIN user u ON pm.sender_id = u.user_id WHERE pm.conversation_id = #{conversationId} AND pm.is_recalled = 0
AND (pm.create_time, pm.id) < (SELECT create_time, id FROM private_message WHERE id = #{beforeMessageId})
ORDER BY pm.create_time DESC, pm.id DESC LIMIT #{pageSize}
